function quoteBasePrice(items: { type: string }[]): number {
  if (
    items.length === 3 &&
    items[0].type === items[1].type &&
    items[1].type === items[2].type
  ) {
    return 60;
  }
  return items.reduce((sum, item) => sum + BASE_PRICES[item.type], 0);
}

export function runScenario(scenario: any): unknown {
  const items = scenario.steps[0].items;
  const basePrice = quoteBasePrice(items);
  const premium = applyFirstInsuranceSurcharge(basePrice) + FIXED_FEE;
  return { results: [{ premium }] };
}
